+                removedLists.add(new ArrayList<>(c.getRemoved()));
+            }
+        });
+
+        StageLoader sl = new StageLoader(table);
+        table.sort();
+
+        // old state: items ["a", "b", "c"] and selected cells ["0", "1", "2"]
